SKILL.md와 프로젝트 컨벤션을 충분히 파악했습니다. 이제 프로필 수정 API 인터페이스 설계를 제공하겠습니다.

---

# 프로필 수정 API 인터페이스 설계

## 1. 현재 스키마 분석 결과

기존 `.graphqls` 파일 및 `.proto` 파일이 없는 초기 상태입니다. 아래 설계는 SKILL.md 컨벤션과 Maum 앱의 소셜/데이팅 도메인 특성을 기반으로 합니다.

---

## 2. GraphQL 스키마 설계

파일 위치: `graphql/src/main/resources/graphql/profile.graphqls`

```graphql
# ─────────────────────────────────────────────
# Enum 타입
# ─────────────────────────────────────────────

enum Gender {
    MALE
    FEMALE
    NON_BINARY
}

enum RelationshipGoal {
    FRIENDSHIP       # 친구
    DATING           # 연애
    MARRIAGE         # 결혼
    CASUAL           # 가벼운 만남
}

enum VoiceCallStyle {
    TALKER           # 말 많은 편
    LISTENER         # 듣는 편
    BALANCED         # 균형
}

# ─────────────────────────────────────────────
# 공통 타입
# ─────────────────────────────────────────────

type ProfileImage {
    imageId: ID!
    url: String!
    order: Int!              # 사진 순서 (0번이 대표 사진)
    isMain: Boolean!
}

type InterestTag {
    tagId: ID!
    name: String!
}

type VoiceIntroduction {
    fileUrl: String
    durationSeconds: Int
    uploadedAt: String
}

# ─────────────────────────────────────────────
# 반환 타입 (Profile)
# ─────────────────────────────────────────────

type Profile {
    userId: ID!
    nickname: String!
    bio: String               # 자기소개 (nullable: 미작성 허용)
    birthYear: Int!
    age: Int!                 # 계산 필드
    gender: Gender!
    height: Int               # cm (nullable: 비공개 허용)
    job: String               # 직업 (nullable)
    location: String          # 활동 지역 (nullable)

    # 소셜/데이팅 특화 필드
    relationshipGoal: RelationshipGoal
    voiceCallStyle: VoiceCallStyle
    interests: [InterestTag!]!
    languages: [String!]!     # 사용 가능한 언어 목록

    # 미디어
    profileImages: [ProfileImage!]!
    voiceIntroduction: VoiceIntroduction  # 음성 자기소개

    # 공개 설정
    isAgePublic: Boolean!
    isHeightPublic: Boolean!
    isJobPublic: Boolean!

    updatedAt: String!
}

type UpdateProfilePayload {
    success: Boolean!
    profile: Profile!
}

# ─────────────────────────────────────────────
# Input 타입
# ─────────────────────────────────────────────

input ProfileImageInput {
    imageId: ID           # null이면 신규 업로드 예정 (presigned URL 발급 후 별도 처리)
    order: Int!
    isMain: Boolean!
}

input UpdateProfileInput {
    # 기본 정보
    nickname: String        # null이면 변경 없음 (부분 수정 지원)
    bio: String             # 빈 문자열("")이면 삭제
    height: Int
    job: String
    location: String

    # 소셜/데이팅 특화
    relationshipGoal: RelationshipGoal
    voiceCallStyle: VoiceCallStyle
    interestTagIds: [ID!]   # 관심사 태그 ID 목록 (전체 교체)
    languages: [String!]    # 언어 목록 (전체 교체)

    # 공개 설정
    isAgePublic: Boolean
    isHeightPublic: Boolean
    isJobPublic: Boolean

    # 프로필 사진 순서 재정렬 (사진 자체 업로드는 별도 mutation)
    profileImages: [ProfileImageInput!]
}

input DeleteProfileImageInput {
    imageId: ID!
}

input UpdateVoiceIntroductionInput {
    fileKey: String!        # S3 업로드 완료 후 전달받은 key
}

# ─────────────────────────────────────────────
# Mutation / Query
# ─────────────────────────────────────────────

extend type Query {
    myProfile: Profile!
    interestTags: [InterestTag!]!   # 선택 가능한 관심사 태그 목록 조회
}

extend type Mutation {
    updateProfile(input: UpdateProfileInput!): UpdateProfilePayload!
    deleteProfileImage(input: DeleteProfileImageInput!): UpdateProfilePayload!
    updateVoiceIntroduction(input: UpdateVoiceIntroductionInput!): UpdateProfilePayload!
    deleteVoiceIntroduction: UpdateProfilePayload!
}
```

---

## 3. gRPC Proto 설계

파일 위치: `protobuf/src/main/proto/profile/profile_service.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// ─────────────────────────────────────────────
// 서비스 정의
// ─────────────────────────────────────────────

service ProfileService {
  rpc GetMyProfile(GetMyProfileRequest) returns (GetMyProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc DeleteProfileImage(DeleteProfileImageRequest) returns (UpdateProfileResponse);
  rpc UpdateVoiceIntroduction(UpdateVoiceIntroductionRequest) returns (UpdateProfileResponse);
  rpc DeleteVoiceIntroduction(DeleteVoiceIntroductionRequest) returns (UpdateProfileResponse);
  rpc ListInterestTags(ListInterestTagsRequest) returns (ListInterestTagsResponse);
}

// ─────────────────────────────────────────────
// Enum
// ─────────────────────────────────────────────

enum Gender {
  GENDER_UNSPECIFIED = 0;
  GENDER_MALE = 1;
  GENDER_FEMALE = 2;
  GENDER_NON_BINARY = 3;
}

enum RelationshipGoal {
  RELATIONSHIP_GOAL_UNSPECIFIED = 0;
  RELATIONSHIP_GOAL_FRIENDSHIP = 1;
  RELATIONSHIP_GOAL_DATING = 2;
  RELATIONSHIP_GOAL_MARRIAGE = 3;
  RELATIONSHIP_GOAL_CASUAL = 4;
}

enum VoiceCallStyle {
  VOICE_CALL_STYLE_UNSPECIFIED = 0;
  VOICE_CALL_STYLE_TALKER = 1;
  VOICE_CALL_STYLE_LISTENER = 2;
  VOICE_CALL_STYLE_BALANCED = 3;
}

// ─────────────────────────────────────────────
// 공통 메시지
// ─────────────────────────────────────────────

message ProfileImage {
  string image_id = 1;
  string url = 2;
  int32 order = 3;
  bool is_main = 4;
}

message InterestTag {
  string tag_id = 1;
  string name = 2;
}

message VoiceIntroduction {
  string file_url = 1;
  int32 duration_seconds = 2;
  string uploaded_at = 3;
}

message ProfileData {
  string user_id = 1;
  string nickname = 2;
  optional string bio = 3;
  int32 birth_year = 4;
  int32 age = 5;
  Gender gender = 6;
  optional int32 height = 7;
  optional string job = 8;
  optional string location = 9;

  RelationshipGoal relationship_goal = 10;
  VoiceCallStyle voice_call_style = 11;
  repeated InterestTag interests = 12;
  repeated string languages = 13;

  repeated ProfileImage profile_images = 14;
  optional VoiceIntroduction voice_introduction = 15;

  bool is_age_public = 16;
  bool is_height_public = 17;
  bool is_job_public = 18;

  string updated_at = 19;
}

// ─────────────────────────────────────────────
// Request / Response 메시지
// ─────────────────────────────────────────────

message GetMyProfileRequest {
  string user_id = 1;
}

message GetMyProfileResponse {
  ProfileData profile = 1;
}

message ProfileImageInput {
  string image_id = 1;
  int32 order = 2;
  bool is_main = 3;
}

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname = 2;
  optional string bio = 3;
  optional int32 height = 4;
  optional string job = 5;
  optional string location = 6;
  optional RelationshipGoal relationship_goal = 7;
  optional VoiceCallStyle voice_call_style = 8;
  repeated string interest_tag_ids = 9;
  repeated string languages = 10;
  optional bool is_age_public = 11;
  optional bool is_height_public = 12;
  optional bool is_job_public = 13;
  repeated ProfileImageInput profile_images = 14;
}

message UpdateProfileResponse {
  bool success = 1;
  ProfileData profile = 2;
}

message DeleteProfileImageRequest {
  string user_id = 1;
  string image_id = 2;
}

message UpdateVoiceIntroductionRequest {
  string user_id = 1;
  string file_key = 2;
}

message DeleteVoiceIntroductionRequest {
  string user_id = 1;
}

message ListInterestTagsRequest {}

message ListInterestTagsResponse {
  repeated InterestTag tags = 1;
}
```

