## 4. GraphQL Controller/Service 스켈레톤

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileGrpcService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(@UserId userId: String): ProfileResponse {
        val response = profileService.getMyProfile(userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    fun interestTags(): List<InterestTagResponse> {
        val response = profileService.listInterestTags()
        return response.tagsList.map { it.toResponse() }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): UpdateProfilePayload {
        val response = profileService.updateProfile(userId, input)
        return UpdateProfilePayload(
            success = response.success,
            profile = response.profile.toResponse(),
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteProfileImage(
        @UserId userId: String,
        @Argument input: DeleteProfileImageInput,
    ): UpdateProfilePayload {
        val response = profileService.deleteProfileImage(userId, input.imageId)
        return UpdateProfilePayload(
            success = response.success,
            profile = response.profile.toResponse(),
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateVoiceIntroduction(
        @UserId userId: String,
        @Argument input: UpdateVoiceIntroductionInput,
    ): UpdateProfilePayload {
        val response = profileService.updateVoiceIntroduction(userId, input.fileKey)
        return UpdateProfilePayload(
            success = response.success,
            profile = response.profile.toResponse(),
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteVoiceIntroduction(@UserId userId: String): UpdateProfilePayload {
        val response = profileService.deleteVoiceIntroduction(userId)
        return UpdateProfilePayload(
            success = response.success,
            profile = response.profile.toResponse(),
        )
    }
}
```

파일 위치: `graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileGrpcService.kt`

```kotlin
@Service
class ProfileGrpcService {
    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getMyProfile(userId: String): GetMyProfileResponse {
        val request = GetMyProfileRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.getMyProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val builder = UpdateProfileRequest.newBuilder().setUserId(userId)
        input.nickname?.let { builder.setNickname(it) }
        input.bio?.let { builder.setBio(it) }
        input.height?.let { builder.setHeight(it) }
        input.job?.let { builder.setJob(it) }
        input.location?.let { builder.setLocation(it) }
        input.relationshipGoal?.let { builder.setRelationshipGoal(it.toProto()) }
        input.voiceCallStyle?.let { builder.setVoiceCallStyle(it.toProto()) }
        input.interestTagIds?.let { builder.addAllInterestTagIds(it) }
        input.languages?.let { builder.addAllLanguages(it) }
        input.isAgePublic?.let { builder.setIsAgePublic(it) }
        input.isHeightPublic?.let { builder.setIsHeightPublic(it) }
        input.isJobPublic?.let { builder.setIsJobPublic(it) }
        input.profileImages?.let { images ->
            builder.addAllProfileImages(images.map { it.toProto() })
        }
        return try {
            stub.updateProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun deleteProfileImage(userId: String, imageId: String): UpdateProfileResponse {
        val request = DeleteProfileImageRequest.newBuilder()
            .setUserId(userId)
            .setImageId(imageId)
            .build()
        return try {
            stub.deleteProfileImage(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateVoiceIntroduction(userId: String, fileKey: String): UpdateProfileResponse {
        val request = UpdateVoiceIntroductionRequest.newBuilder()
            .setUserId(userId)
            .setFileKey(fileKey)
            .build()
        return try {
            stub.updateVoiceIntroduction(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun deleteVoiceIntroduction(userId: String): UpdateProfileResponse {
        val request = DeleteVoiceIntroductionRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.deleteVoiceIntroduction(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun listInterestTags(): ListInterestTagsResponse {
        val request = ListInterestTagsRequest.newBuilder().build()
        return try {
            stub.listInterestTags(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

